INSERT INTO `article_translations` VALUES ('04df119c-6899-4612-84c4-d88113cc75a7', 'a6ef4156-f64a-4509-b097-963e073f3492', 'vi', 'Chuẩn bị Tài liệu', NULL, 'Chuẩn bị bản sao hộ chiếu (còn hạn 6+ tháng), ảnh chân dung và các tài liệu bổ sung cho dịch vụ VIP.', '2026-06-23 09:04:16.356', '2026-06-23 09:04:16.356');
INSERT INTO `article_translations` VALUES ('0c6e6456-dfd5-41fc-b699-0b1f79da8da8', 'bf3f68a6-77f8-4062-997f-0d1b774db565', 'en', 'Choose Your Visa', NULL, 'Select visa type, processing speed, and number of applicants on the online form.', '2026-06-23 09:04:16.339', '2026-06-23 09:04:16.339');
INSERT INTO `article_translations` VALUES ('1e21fe10-3158-4073-aea1-21270e4d7208', '7b389839-ac31-4d57-bb9f-9860379f74bd', 'vi', 'Hướng Dẫn Thanh Toán', 'Thanh toán trực tuyến an toàn cho đơn xin visa Việt Nam.', '<p>Thanh toán bằng Visa, Mastercard hoặc PayPal. Tất cả giao dịch được xử lý bằng USD.</p>', '2026-06-23 02:55:39.134', '2026-06-24 13:20:25.906');
INSERT INTO `article_translations` VALUES ('1f2654a1-6fbf-4fd6-b911-d2fffd263f3c', 'd2bc1a16-897b-4b9c-b555-0bc7f0a8a777', 'en', 'Portrait Photo', NULL, 'Recent photo on white background, passport-style dimensions.', '2026-06-23 09:04:16.446', '2026-06-23 09:04:16.446');
INSERT INTO `article_translations` VALUES ('274dce19-885e-490d-8acb-1e0d9a6660be', '2a98b772-2fba-46ff-a893-f9b1cc89a43a', 'vi', 'Bản sao Hộ chiếu', NULL, 'Bản scan trang thông tin với ít nhất 6 tháng hiệu lực.', '2026-06-23 09:04:16.428', '2026-06-23 09:04:16.428');
INSERT INTO `article_translations` VALUES ('38c37318-c749-4611-bf4c-672873760878', '0ffa0515-8338-428c-975b-914a1ec41d95', 'vi', 'Dịch Vụ Bổ Sung', 'Các dịch vụ tùy chọn giúp tăng tốc trải nghiệm sân bay.', '<p>Dịch vụ VIP Fast-track tại sân bay, đưa đón xe, đặt phòng khách sạn và các dịch vụ du lịch cao cấp khác.</p>', '2026-06-23 02:55:39.084', '2026-06-24 13:20:25.863');
INSERT INTO `article_translations` VALUES ('3adf3d86-413b-4b87-bd15-411d9274d4eb', '71e74a91-92b1-415e-8341-5076fe75c666', 'vi', 'Nhận E-Visa qua Email', NULL, 'Xử lý tiêu chuẩn mất 7 ngày làm việc. Lựa chọn khẩn cấp từ 4 giờ đến 1 ngày làm việc.', '2026-06-23 09:04:16.409', '2026-06-23 09:04:16.409');
INSERT INTO `article_translations` VALUES ('44b79ab0-23a1-4ba7-9ee7-b6172217995c', '3bfeb9f7-24f3-454d-adfb-b6314de6100b', 'en', 'Application Form', NULL, 'Completed online — no paper form required for e-visa.', '2026-06-23 09:04:16.466', '2026-06-23 09:04:16.466');
INSERT INTO `article_translations` VALUES ('583fa7a9-60f7-442d-b45d-ec38cc4b3040', 'f3df6153-65fa-498c-972f-1ebf2dfea8b1', 'en', 'Review & Pay', NULL, 'Confirm pricing breakdown — no hidden fees — then pay via card or PayPal in USD.', '2026-06-23 09:04:16.390', '2026-06-23 09:04:16.390');
INSERT INTO `article_translations` VALUES ('7095a399-b87d-4b1d-80e6-022dc1346457', 'd2bc1a16-897b-4b9c-b555-0bc7f0a8a777', 'vi', 'Ảnh chân dung', NULL, 'Ảnh chụp gần đây trên nền trắng, kích thước chuẩn hộ chiếu.', '2026-06-23 09:04:16.446', '2026-06-23 09:04:16.446');
INSERT INTO `article_translations` VALUES ('8a42046c-2801-45ff-87d9-8c25d6cdd2eb', 'f3df6153-65fa-498c-972f-1ebf2dfea8b1', 'vi', 'Kiểm tra & Thanh toán', NULL, 'Xác nhận chi phí — không có phí ẩn — sau đó thanh toán qua thẻ hoặc PayPal bằng USD.', '2026-06-23 09:04:16.390', '2026-06-23 09:04:16.390');
INSERT INTO `article_translations` VALUES ('8bdaa855-444e-4881-9c9f-c732bdbc6337', 'a6ef4156-f64a-4509-b097-963e073f3492', 'en', 'Prepare Documents', NULL, 'Gather passport copy (6+ months validity), portrait photo, and any extra documents for VIP service.', '2026-06-23 09:04:16.356', '2026-06-23 09:04:16.356');
INSERT INTO `article_translations` VALUES ('ad703a6e-ed2a-4038-b684-80e88f13b065', '3bfeb9f7-24f3-454d-adfb-b6314de6100b', 'vi', 'Đơn xin Visa', NULL, 'Hoàn thành trực tuyến — không yêu cầu đơn giấy đối với e-visa.', '2026-06-23 09:04:16.466', '2026-06-23 09:04:16.466');
INSERT INTO `article_translations` VALUES ('bc37d1b8-bb2f-4fbc-b1ee-f3e5c56ab355', '7ad1f500-9920-4c0a-a3c2-7eca1501bad9', 'vi', 'Miễn Thị Thực', 'Kiểm tra xem quốc tịch của bạn có được miễn visa vào Việt Nam không.', '<p>Việt Nam miễn thị thực cho công dân của hơn 25 quốc gia theo các hiệp định song phương và đơn phương.</p>', '2026-06-23 02:55:39.101', '2026-06-24 13:20:25.876');
INSERT INTO `article_translations` VALUES ('c945727a-80f6-4502-82dd-e470786d8353', 'c03a0283-1925-4580-8c5e-36d85954b1b7', 'vi', 'Điền thông tin', NULL, 'Nhập thông tin hộ chiếu cho từng người và tải lên các tệp bắt buộc một cách an toàn.', '2026-06-23 09:04:16.374', '2026-06-23 09:04:16.374');
INSERT INTO `article_translations` VALUES ('cc58171e-e477-4075-bdbe-a1124fe40274', 'bf3f68a6-77f8-4062-997f-0d1b774db565', 'vi', 'Chọn loại Visa', NULL, 'Chọn loại visa, tốc độ xử lý và số lượng người nộp đơn trên biểu mẫu trực tuyến.', '2026-06-23 09:04:16.339', '2026-06-23 09:04:16.339');
INSERT INTO `article_translations` VALUES ('de68791d-a47f-4d4b-bd91-84cb0d4f330b', '6d36eb1a-9278-45ec-8cb8-63fe5bb94db0', 'vi', 'Gia Hạn Visa', 'Cách gia hạn thời gian lưu trú khi bạn đang ở Việt Nam.', '<p>Tìm hiểu quy trình gia hạn visa Việt Nam từ trong nước.</p>', '2026-06-23 02:55:39.114', '2026-06-24 13:20:25.891');
INSERT INTO `article_translations` VALUES ('ee43e319-8f49-4716-a894-d9208fe3d33e', '2a98b772-2fba-46ff-a893-f9b1cc89a43a', 'en', 'Passport Copy', NULL, 'Bio-page scan with at least 6 months validity remaining.', '2026-06-23 09:04:16.428', '2026-06-23 09:04:16.428');
INSERT INTO `article_translations` VALUES ('f67fbe15-adf1-46d8-8a68-139ccc28bab4', '71e74a91-92b1-415e-8341-5076fe75c666', 'en', 'Receive E-Visa by Email', NULL, 'Standard processing takes 7 working days. Urgent options from 4 hours to 1 working day.', '2026-06-23 09:04:16.409', '2026-06-23 09:04:16.409');
INSERT INTO `article_translations` VALUES ('f7deb1d2-47c8-4f57-bb9d-0996a9f06b84', 'c03a0283-1925-4580-8c5e-36d85954b1b7', 'en', 'Fill Application Details', NULL, 'Enter passport details for each applicant and upload required files securely.', '2026-06-23 09:04:16.374', '2026-06-23 09:04:16.374');
INSERT INTO `articles` VALUES ('0ffa0515-8338-428c-975b-914a1ec41d95', 'extra-services', 'Extra Services', 'Optional add-ons to speed up your airport experience.', '<p>VIP Airport Fast-track, Car Pick-up Service, Hotel Reservation and other premium travel services.</p>', NULL, 'guide', '/images/guide/services-cover.jpg', '2026-06-23 02:55:39.076', '2026-06-24 13:20:25.856', 1, '{}');
