INSERT INTO `articles` VALUES ('7ad1f500-9920-4c0a-a3c2-7eca1501bad9', 'visa-exemptions', 'Visa Exemptions', 'Check if your nationality qualifies for visa-free entry to Vietnam.', '<p>Vietnam grants visa-free entry to citizens of 25+ countries under bilateral and unilateral agreements.</p>', NULL, 'guide', '/images/guide/exemptions-cover.jpg', '2026-06-23 02:55:39.092', '2026-06-24 13:20:25.870', 2, '{\"coverImage\": \"/images/guide/exemptions-cover.jpg\"}');
