INSERT INTO `background_jobs` VALUES ('61f2c59f-d75b-48f0-8cef-1340e1cc5264', 'SEND_CAMPAIGN_EMAIL', '{\"email\": \"vietnm.oes@gmail.com\", \"subject\": \"Cập Nhật Dịch Vụ E-Visa Khẩn\", \"htmlContent\": \"<h2><strong>Cập Nhật Dịch Vụ E-Visa Khẩn</strong></h2><p>Hệ thống đang bảo trì dịch vụ tự động tạo bài viết. Dưới đây là thông tin mặc định về dịch vụ e-Visa khẩn.</p><img src=\\\"https://res.cloudinary.com/dbzaqlxvc/image/upload/v1782207802/fastvisa/campaigns/v144exlao8s5u72aqlgv.jpg\\\" alt=\\\"Travel\\\"><p></p>\"}', 'COMPLETED', NULL, 1, '2026-06-23 16:17:00.031', '2026-06-23 16:17:12.956');
INSERT INTO `background_jobs` VALUES ('61fad191-4e1d-462f-bf40-9f5b738ce255', 'SEND_CAMPAIGN_EMAIL', '{\"email\": \"vietnm.oes@gmail.com\", \"subject\": \"Chào bạn từ FASTVISA,\", \"htmlContent\": \"<h2>Chào bạn từ FASTVISA,</h2><p>Hy vọng bạn đã có một tuần làm việc hiệu quả. Tại FASTVISA, chúng tôi luôn nỗ lực cập nhật những thay đổi mới nhất để hành trình của bạn trở nên suôn sẻ và thuận tiện hơn.</p><img src=\\\"https://res.cloudinary.com/dbzaqlxvc/image/upload/v1782375083/fastvisa/campaigns/rja1iu6eeanrzqziwazp.jpg\\\" alt=\\\"Travel Landscape\\\"><h2>Dịch vụ E-Visa Khẩn: Giải pháp cho người bận rộn</h2><p>Bạn có kế hoạch công tác đột xuất hoặc chuyến đi bất ngờ? Đừng để nỗi lo thủ tục làm gián đoạn lịch trình của bạn. Với <strong>Dịch vụ E-Visa Khẩn</strong> tại FASTVISA, chúng tôi cam kết:</p><ul><li><p>Thời gian xử lý rút ngắn tối đa (từ 4-24 giờ làm việc).</p></li><li><p>Quy trình xét duyệt ưu tiên, giảm thiểu rủi ro bị từ chối hồ sơ.</p></li><li><p>Hỗ trợ tư vấn 24/7 bởi đội ngũ chuyên gia dày dạn kinh nghiệm.</p></li></ul><h2>Cập nhật chính sách &amp; Mẹo du lịch</h2><p>Chúng tôi vừa tổng hợp một số thay đổi quan trọng về quy định xuất nhập cảnh tại các quốc gia trọng điểm trong tháng này. Đặc biệt lưu ý:</p><ul><li><p><strong>Cập nhật chính sách:</strong> Nhiều quốc gia đã áp dụng hệ thống xác thực điện tử mới, yêu cầu du khách khai báo thông tin trước ít nhất 72 giờ trước khi khởi hành.</p></li><li><p><strong>Mẹo hữu ích:</strong> Luôn lưu giữ bản sao kỹ thuật số (scan) của Visa và hộ chiếu trên dịch vụ lưu trữ đám mây để sử dụng trong trường hợp khẩn cấp.</p></li></ul><p>Nếu bạn cần hỗ trợ bất kỳ hồ sơ nào hoặc có câu hỏi về quy định mới, hãy phản hồi email này hoặc liên hệ hotline của chúng tôi để được giải đáp ngay lập tức.</p><p>Trân trọng,<br><strong>Đội ngũ Chuyên gia FASTVISA</strong></p><p> © 2023 FASTVISA. Tất cả các quyền được bảo lưu.</p>\"}', 'COMPLETED', NULL, 1, '2026-06-25 08:38:00.028', '2026-06-25 08:38:05.991');
