INSERT INTO `background_jobs` VALUES ('9e723de2-ef91-4ca0-ac89-232838aa0acd', 'SEND_CAMPAIGN_EMAIL', '{\"email\": \"vietnm.oes@gmail.com\", \"subject\": \"Chào bạn từ FASTVISA,\", \"htmlContent\": \"<h2>Chào bạn từ FASTVISA,</h2><p>Hy vọng bạn đang có những kế hoạch du lịch tuyệt vời cho hành trình sắp tới. Hôm nay, FASTVISA gửi đến bạn những cập nhật quan trọng để đảm bảo chuyến đi của bạn luôn suôn sẻ.</p><img src=\\\"https://res.cloudinary.com/dbzaqlxvc/image/upload/v1782374706/fastvisa/campaigns/gmz5hlg8plie4dqkpav3.jpg\\\" alt=\\\"Travel destination\\\"><h2>Dịch vụ E-Visa khẩn</h2><p>Bạn cần khởi hành gấp nhưng chưa có thị thực? FASTVISA hiện đã tối ưu hóa quy trình <strong>Dịch vụ E-Visa khẩn</strong>, cam kết:</p><ul><li><p>Xử lý hồ sơ ưu tiên trong vòng 4-24 giờ làm việc.</p></li><li><p>Hỗ trợ kiểm tra hồ sơ chuyên sâu, giảm thiểu tỉ lệ từ chối.</p></li><li><p>Cập nhật trạng thái thời gian thực qua hotline chuyên trách.</p></li></ul><h2>Mẹo du lịch &amp; Cập nhật chính sách</h2><p>Các quy định về nhập cảnh đang có nhiều thay đổi linh hoạt trong tháng này. Một số lưu ý nhỏ giúp hành trình của bạn thuận lợi hơn:</p><ul><li><p><strong>Kiểm tra thời hạn hộ chiếu:</strong> Luôn đảm bảo hộ chiếu của bạn còn hạn ít nhất 6 tháng so với ngày dự định rời khỏi quốc gia đến.</p></li><li><p><strong>Lưu trữ bản mềm:</strong> Luôn lưu sẵn file PDF của E-Visa và bảo hiểm du lịch trong điện thoại để xuất trình khi cần thiết.</p></li></ul><p>Nếu bạn cần hỗ trợ bất kỳ thủ tục nào hoặc muốn tư vấn lộ trình visa cho điểm đến sắp tới, đừng ngần ngại phản hồi email này.</p><p><strong>Trân trọng,<br>Đội ngũ chuyên gia FASTVISA</strong></p><p>© 2024 FASTVISA. Tất cả quyền được bảo lưu.</p>\"}', 'COMPLETED', NULL, 1, '2026-06-25 08:26:00.055', '2026-06-25 08:26:05.451');
INSERT INTO `background_jobs` VALUES ('9e94cbbd-8c5a-46d6-aef7-0f685f433f0b', 'SEND_CAMPAIGN_EMAIL', '{\"email\": \"subscriber27@example.com\", \"subject\": \"AI Content Creation: Viết nội dung thông minh\", \"htmlContent\": \"<h2>AI Content Creation: Viết nội dung thông minh</h2><p>Sử dụng AI để tạo ra hàng ngàn bài viết chuẩn SEO trong thời gian ngắn mà vẫn đảm bảo chất lượng và độ độc đáo.</p><img src=\'https://images.unsplash.com/photo-1655393001768-d946c98d6958?auto=format&fit=crop&q=80&w=800\' alt=\'AI Content\' />\"}', 'COMPLETED', NULL, 3, '2026-06-23 08:08:00.031', '2026-06-23 08:08:54.108');
INSERT INTO `background_jobs` VALUES ('9eca371f-3a74-4a8c-8f6c-2065fb995489', 'SEND_CAMPAIGN_EMAIL', '{\"email\": \"subscriber27@example.com\", \"subject\": \"Phân tích dữ liệu lớn với AI\", \"htmlContent\": \"<h2>Phân tích dữ liệu lớn với AI</h2><p>Dữ liệu là mỏ vàng. Hãy để AI giúp bạn đào sâu và phân tích dữ liệu khổng lồ để đưa ra các quyết định kinh doanh chính xác nhất.</p><img src=\'https://images.unsplash.com/photo-1551288049-bebda4e38f71?auto=format&fit=crop&q=80&w=800\' alt=\'Data Analytics\' />\"}', 'FAILED', 'Invalid login: 454-4.7.0 Too many login attempts, please try again later. For more information,\n454-4.7.0 go to\n454 4.7.0  https://support.google.com/mail/answer/7126229 98e67ed59e1d1-37d77b1d1a3sm7014314a91.15 - gsmtp', 2, '2026-06-23 08:10:00.035', '2026-06-23 08:10:30.842');
