INSERT INTO `background_jobs` VALUES ('bd79fa85-a639-4115-b58c-231e0206bcce', 'SEND_CAMPAIGN_EMAIL', '{\"email\": \"subscriber6@example.com\", \"subject\": \"Khám phá tiềm năng AI trong Automation\", \"htmlContent\": \"<h2>Khám phá tiềm năng AI trong Automation</h2><p>Hệ thống tự động hóa được tích hợp AI giúp doanh nghiệp tiết kiệm hàng nghìn giờ làm việc mỗi tháng.</p><img src=\'https://images.unsplash.com/photo-1518770660439-4636190af475?auto=format&fit=crop&q=80&w=800\' alt=\'AI Automation\' />\"}', 'COMPLETED', NULL, 3, '2026-06-23 08:02:00.019', '2026-06-23 08:03:10.798');
