INSERT INTO `background_jobs` VALUES ('d199b0f4-61a8-493e-8fae-2c3ccfaa2e35', 'SEND_CAMPAIGN_EMAIL', '{\"email\": \"vietnm.oes@gmail.com\", \"subject\": \"Chào bạn từ FASTVISA,\", \"htmlContent\": \"<h2>Chào bạn từ FASTVISA,</h2><p>Hy vọng bạn đang có những kế hoạch du lịch tuyệt vời cho hành trình sắp tới. Hôm nay, FASTVISA gửi đến bạn những cập nhật quan trọng để đảm bảo chuyến đi của bạn luôn suôn sẻ.</p><img src=\\\"https://res.cloudinary.com/dbzaqlxvc/image/upload/v1782374706/fastvisa/campaigns/gmz5hlg8plie4dqkpav3.jpg\\\" alt=\\\"Travel destination\\\"><h2>Dịch vụ E-Visa khẩn</h2><p>Bạn cần khởi hành gấp nhưng chưa có thị thực? FASTVISA hiện đã tối ưu hóa quy trình <strong>Dịch vụ E-Visa khẩn</strong>, cam kết:</p><ul><li><p>Xử lý hồ sơ ưu tiên trong vòng 4-24 giờ làm việc.</p></li><li><p>Hỗ trợ kiểm tra hồ sơ chuyên sâu, giảm thiểu tỉ lệ từ chối.</p></li><li><p>Cập nhật trạng thái thời gian thực qua hotline chuyên trách.</p></li></ul><h2>Mẹo du lịch &amp; Cập nhật chính sách</h2><p>Các quy định về nhập cảnh đang có nhiều thay đổi linh hoạt trong tháng này. Một số lưu ý nhỏ giúp hành trình của bạn thuận lợi hơn:</p><ul><li><p><strong>Kiểm tra thời hạn hộ chiếu:</strong> Luôn đảm bảo hộ chiếu của bạn còn hạn ít nhất 6 tháng so với ngày dự định rời khỏi quốc gia đến.</p></li><li><p><strong>Lưu trữ bản mềm:</strong> Luôn lưu sẵn file PDF của E-Visa và bảo hiểm du lịch trong điện thoại để xuất trình khi cần thiết.</p></li></ul><p>Nếu bạn cần hỗ trợ bất kỳ thủ tục nào hoặc muốn tư vấn lộ trình visa cho điểm đến sắp tới, đừng ngần ngại phản hồi email này.</p><p><strong>Trân trọng,<br>Đội ngũ chuyên gia FASTVISA</strong></p><p>© 2024 FASTVISA. Tất cả quyền được bảo lưu.</p>\"}', 'COMPLETED', NULL, 1, '2026-06-29 14:23:00.025', '2026-06-29 14:23:07.398');
