INSERT INTO `eligibility_rules` VALUES ('e378f78d-ef0b-45a4-9b52-30a07f0645ad', 'CN', 1, NULL, '2026-06-23 02:55:38.888', '2026-06-24 13:20:25.612');
INSERT INTO `faq_translations` VALUES ('6b48b39e-a184-4359-ae03-c75ee57615fa', 'aaf323ed-08d8-437d-9cdb-aedfc24a13ce', 'en', 'How fast can I get my visa?', 'Normal processing is 7 working days. Urgent options: 4 days, 2 days, 1 day, or 4 working hours depending on visa type.', '2026-06-23 09:04:16.507', '2026-06-23 09:04:16.507');
INSERT INTO `faq_translations` VALUES ('7d7b697d-ae8b-4fbe-b0a5-286abcaec123', '565e75cc-82b7-4ff6-a67c-db6c2dbae897', 'en', 'What is a Vietnam E-visa?', 'An electronic visa issued by the Vietnamese government. You receive a PDF approval letter to present at immigration.', '2026-06-23 09:04:16.487', '2026-06-23 09:04:16.487');
INSERT INTO `faq_translations` VALUES ('9a08b6de-4306-4d28-9360-31591919d500', '99e351bd-5b74-49ad-98b9-5a38fd379f04', 'vi', 'Những tài liệu nào là cần thiết cho việc nộp đơn e-Visa?', '<p>Bạn sẽ cần các tài liệu sau:</p><ol><li>Hộ chiếu hợp lệ còn hạn ít nhất 6 tháng.</li><li>Một ảnh chân dung gần đây (nền trắng).</li></ol>', '2026-06-23 02:55:39.180', '2026-06-24 13:20:25.941');
INSERT INTO `faq_translations` VALUES ('a752aea8-31d8-496e-99dd-3711c5d5d6eb', 'b6764b0b-74ba-42d0-89b3-66a9dd27460e', 'en', 'Are there additional costs?', 'Total = base service fee + processing surcharge + optional extras (e.g. VIP fast-track +$55). Stamping fee at airport is separate ($25 tourist / $50 business).', '2026-06-23 09:04:16.525', '2026-06-23 09:04:16.525');
INSERT INTO `faq_translations` VALUES ('b9b94eeb-2dc1-400e-8189-276b04a94515', 'b6764b0b-74ba-42d0-89b3-66a9dd27460e', 'vi', 'Có chi phí phát sinh không?', 'Tổng = phí dịch vụ cơ bản + phụ phí xử lý + dịch vụ tùy chọn (ví dụ: VIP fast-track +$55). Phí dán tem tại sân bay được tính riêng (25$ du lịch / 50$ công tác).', '2026-06-23 09:04:16.525', '2026-06-23 09:04:16.525');
INSERT INTO `faq_translations` VALUES ('bc606aa7-50d4-444e-9c59-aa2655860626', '565e75cc-82b7-4ff6-a67c-db6c2dbae897', 'vi', 'E-visa Việt Nam là gì?', 'Là thị thực điện tử do chính phủ Việt Nam cấp. Bạn sẽ nhận được thư chấp thuận dưới dạng PDF để xuất trình tại cửa khẩu.', '2026-06-23 09:04:16.487', '2026-06-23 09:04:16.487');
INSERT INTO `faq_translations` VALUES ('e76503b2-7d10-46da-9103-e827d526b6a0', 'aaf323ed-08d8-437d-9cdb-aedfc24a13ce', 'vi', 'Tôi có thể nhận visa nhanh cỡ nào?', 'Thời gian xử lý thông thường là 7 ngày làm việc. Tùy chọn khẩn cấp: 4 ngày, 2 ngày, 1 ngày hoặc 4 giờ làm việc tùy loại visa.', '2026-06-23 09:04:16.507', '2026-06-23 09:04:16.507');
INSERT INTO `faq_translations` VALUES ('fb3d761c-d1b1-4322-9172-cb6f1c76ae43', '34914ba3-f7e9-4956-8f1c-e856502a3bd9', 'vi', 'Mất bao lâu để nhận được e-Visa Việt Nam?', '<p>Thời gian xử lý tiêu chuẩn là <strong>3-5 ngày làm việc</strong>. Tuy nhiên, nếu bạn cần gấp, chúng tôi cung cấp các tùy chọn xử lý khẩn cấp:</p><ul><li>Khẩn (2 ngày làm việc)</li><li>Rất Khẩn (4-8 giờ làm việc)</li></ul>', '2026-06-23 02:55:39.159', '2026-06-24 13:20:25.926');
INSERT INTO `faqs` VALUES ('34914ba3-f7e9-4956-8f1c-e856502a3bd9', 'general', 'How long does it take to get a Vietnam e-Visa?', '<p>The standard processing time is <strong>3-5 working days</strong>. However, if you need it sooner, we offer urgent processing options:</p><ul><li>Urgent (2-working days)</li><li>Super Urgent (4-8 working hours)</li></ul>', 1, 1, NULL, '2026-06-23 02:55:39.148', '2026-06-24 13:20:25.918');
INSERT INTO `faqs` VALUES ('565e75cc-82b7-4ff6-a67c-db6c2dbae897', 'how-to-apply', 'What is a Vietnam E-visa?', 'An electronic visa issued by the Vietnamese government. You receive a PDF approval letter to present at immigration.', 1, 1, NULL, '2026-06-23 09:04:16.477', '2026-06-23 09:04:16.477');
INSERT INTO `faqs` VALUES ('99e351bd-5b74-49ad-98b9-5a38fd379f04', 'general', 'What documents are required for the e-Visa application?', '<p>You will need the following documents:</p><ol><li>A valid passport with at least 6 months validity.</li><li>A recent portrait photo (white background).</li></ol>', 2, 1, NULL, '2026-06-23 02:55:39.170', '2026-06-24 13:20:25.934');
INSERT INTO `faqs` VALUES ('aaf323ed-08d8-437d-9cdb-aedfc24a13ce', 'how-to-apply', 'How fast can I get my visa?', 'Normal processing is 7 working days. Urgent options: 4 days, 2 days, 1 day, or 4 working hours depending on visa type.', 2, 1, NULL, '2026-06-23 09:04:16.498', '2026-06-23 09:04:16.498');
INSERT INTO `faqs` VALUES ('b6764b0b-74ba-42d0-89b3-66a9dd27460e', 'how-to-apply', 'Are there additional costs?', 'Total = base service fee + processing surcharge + optional extras (e.g. VIP fast-track +$55). Stamping fee at airport is separate ($25 tourist / $50 business).', 3, 1, NULL, '2026-06-23 09:04:16.515', '2026-06-23 09:04:16.515');
