INSERT INTO `newsletter_campaigns` VALUES ('081b361e-d4fc-410d-b493-111e89bc45e0', 2, 'Chào bạn từ FASTVISA,', '<h2>Chào bạn từ FASTVISA,</h2><p>Hy vọng bạn đã có một tuần làm việc hiệu quả. Tại FASTVISA, chúng tôi luôn nỗ lực cập nhật những thay đổi mới nhất để hành trình của bạn trở nên suôn sẻ và thuận tiện hơn.</p><img src=\"https://res.cloudinary.com/dbzaqlxvc/image/upload/v1782375083/fastvisa/campaigns/rja1iu6eeanrzqziwazp.jpg\" alt=\"Travel Landscape\"><h2>Dịch vụ E-Visa Khẩn: Giải pháp cho người bận rộn</h2><p>Bạn có kế hoạch công tác đột xuất hoặc chuyến đi bất ngờ? Đừng để nỗi lo thủ tục làm gián đoạn lịch trình của bạn. Với <strong>Dịch vụ E-Visa Khẩn</strong> tại FASTVISA, chúng tôi cam kết:</p><ul><li><p>Thời gian xử lý rút ngắn tối đa (từ 4-24 giờ làm việc).</p></li><li><p>Quy trình xét duyệt ưu tiên, giảm thiểu rủi ro bị từ chối hồ sơ.</p></li><li><p>Hỗ trợ tư vấn 24/7 bởi đội ngũ chuyên gia dày dạn kinh nghiệm.</p></li></ul><h2>Cập nhật chính sách &amp; Mẹo du lịch</h2><p>Chúng tôi vừa tổng hợp một số thay đổi quan trọng về quy định xuất nhập cảnh tại các quốc gia trọng điểm trong tháng này. Đặc biệt lưu ý:</p><ul><li><p><strong>Cập nhật chính sách:</strong> Nhiều quốc gia đã áp dụng hệ thống xác thực điện tử mới, yêu cầu du khách khai báo thông tin trước ít nhất 72 giờ trước khi khởi hành.</p></li><li><p><strong>Mẹo hữu ích:</strong> Luôn lưu giữ bản sao kỹ thuật số (scan) của Visa và hộ chiếu trên dịch vụ lưu trữ đám mây để sử dụng trong trường hợp khẩn cấp.</p></li></ul><p>Nếu bạn cần hỗ trợ bất kỳ hồ sơ nào hoặc có câu hỏi về quy định mới, hãy phản hồi email này hoặc liên hệ hotline của chúng tôi để được giải đáp ngay lập tức.</p><p>Trân trọng,<br><strong>Đội ngũ Chuyên gia FASTVISA</strong></p><p> © 2023 FASTVISA. Tất cả các quyền được bảo lưu.</p>', '2026-06-29 14:25:00.007', '2026-06-25 08:11:25.967', '2026-06-29 14:25:00.013');
INSERT INTO `newsletter_campaigns` VALUES ('db0bfa57-a6b5-49a2-bdf3-af9f7a5cf221', 1, 'Chào bạn từ FASTVISA,', '<h2>Chào bạn từ FASTVISA,</h2><p>Hy vọng bạn đang có những kế hoạch du lịch tuyệt vời cho hành trình sắp tới. Hôm nay, FASTVISA gửi đến bạn những cập nhật quan trọng để đảm bảo chuyến đi của bạn luôn suôn sẻ.</p><img src=\"https://res.cloudinary.com/dbzaqlxvc/image/upload/v1782374706/fastvisa/campaigns/gmz5hlg8plie4dqkpav3.jpg\" alt=\"Travel destination\"><h2>Dịch vụ E-Visa khẩn</h2><p>Bạn cần khởi hành gấp nhưng chưa có thị thực? FASTVISA hiện đã tối ưu hóa quy trình <strong>Dịch vụ E-Visa khẩn</strong>, cam kết:</p><ul><li><p>Xử lý hồ sơ ưu tiên trong vòng 4-24 giờ làm việc.</p></li><li><p>Hỗ trợ kiểm tra hồ sơ chuyên sâu, giảm thiểu tỉ lệ từ chối.</p></li><li><p>Cập nhật trạng thái thời gian thực qua hotline chuyên trách.</p></li></ul><h2>Mẹo du lịch &amp; Cập nhật chính sách</h2><p>Các quy định về nhập cảnh đang có nhiều thay đổi linh hoạt trong tháng này. Một số lưu ý nhỏ giúp hành trình của bạn thuận lợi hơn:</p><ul><li><p><strong>Kiểm tra thời hạn hộ chiếu:</strong> Luôn đảm bảo hộ chiếu của bạn còn hạn ít nhất 6 tháng so với ngày dự định rời khỏi quốc gia đến.</p></li><li><p><strong>Lưu trữ bản mềm:</strong> Luôn lưu sẵn file PDF của E-Visa và bảo hiểm du lịch trong điện thoại để xuất trình khi cần thiết.</p></li></ul><p>Nếu bạn cần hỗ trợ bất kỳ thủ tục nào hoặc muốn tư vấn lộ trình visa cho điểm đến sắp tới, đừng ngần ngại phản hồi email này.</p><p><strong>Trân trọng,<br>Đội ngũ chuyên gia FASTVISA</strong></p><p>© 2024 FASTVISA. Tất cả quyền được bảo lưu.</p>', '2026-06-29 14:23:00.006', '2026-06-25 08:05:10.372', '2026-06-29 14:23:00.015');
