INSERT INTO `page_settings` VALUES ('0a91f029-02d1-4d10-ba9a-7fb2cf8bede3', 'HOME_HOW_IT_WORKS', '[{\"icon\": \"clipboard\", \"step\": 1, \"title\": {\"en\": \"Complete Online Form\", \"ko\": \"온라인 신청서 작성\", \"vi\": \"Điền Đơn Trực Tuyến\"}, \"description\": {\"en\": \"Provide your passport details, travel dates, and select your processing time through our secure portal.\", \"ko\": \"보안 포털을 통해 여권 정보, 여행 날짜를 제공하고 처리 시간을 선택하세요.\", \"vi\": \"Cung cấp thông tin hộ chiếu, ngày đi và chọn thời gian xử lý qua cổng thông tin bảo mật.\"}}, {\"icon\": \"file-text\", \"step\": 2, \"title\": {\"en\": \"Upload Documents\", \"ko\": \"서류 업로드\", \"vi\": \"Tải Lên Tài Liệu\"}, \"description\": {\"en\": \"Easily upload a photo of your passport data page and a recent portrait photo from your device.\", \"ko\": \"기기에서 여권 정보 페이지 사진과 최근 인물 사진을 쉽게 업로드하세요.\", \"vi\": \"Dễ dàng tải lên ảnh trang thông tin hộ chiếu và ảnh chân dung từ thiết bị của bạn.\"}}, {\"icon\": \"credit-card\", \"step\": 3, \"title\": {\"en\": \"Pay Securely\", \"ko\": \"안전한 결제\", \"vi\": \"Thanh Toán An Toàn\"}, \"description\": {\"en\": \"Pay the service fee using Visa, Mastercard, or PayPal. All transactions are fully encrypted.\", \"ko\": \"Visa, Mastercard 또는 PayPal을 사용하여 서비스 요금을 결제하세요. 모든 거래는 암호화됩니다.\", \"vi\": \"Thanh toán phí dịch vụ bằng Visa, Mastercard hoặc PayPal. Mọi giao dịch đều được mã hóa.\"}}, {\"icon\": \"mail\", \"step\": 4, \"title\": {\"en\": \"Receive E-Visa\", \"ko\": \"E-Visa 수령\", \"vi\": \"Nhận E-Visa\"}, \"description\": {\"en\": \"Get your approved Vietnam e-Visa via email in PDF format. Print it out and present it at immigration.\", \"ko\": \"승인된 베트남 e-Visa를 이메일로 PDF 형식으로 받으세요. 출력하여 출입국 심사대에서 제시하세요.\", \"vi\": \"Nhận e-Visa Việt Nam đã được duyệt qua email dưới dạng PDF. In ra và xuất trình tại cửa khẩu.\"}}]', '2026-06-23 02:55:39.503', '2026-06-24 13:20:26.214');
INSERT INTO `page_settings` VALUES ('106e41ef-51f6-4f50-a2eb-c3e34adf6c1d', 'guide-fees', '{\"disclaimer\": {\"title\": {\"en\": \"Service Fee vs. Government Stamping Fee — Important Distinction\", \"ko\": \"서비스 수수료 vs. 정부 스탬프 수수료 — 중요한 차이점\", \"vi\": \"Phí dịch vụ vs. Phí dán tem chính phủ — Phân biệt quan trọng\"}, \"govFee\": {\"en\": \"Government Stamping Fee\", \"ko\": \"정부 스탬프 수수료\", \"vi\": \"Phí dán tem chính phủ\"}, \"serviceFee\": {\"en\": \"Service Fee\", \"ko\": \"서비스 수수료\", \"vi\": \"Phí dịch vụ\"}, \"govFeeDesc1\": {\"en\": \" (paid in \", \"ko\": \" (\", \"vi\": \" (thanh toán bằng \"}, \"govFeeDesc2\": {\"en\": \"exact cash USD\", \"ko\": \"정확한 달러 현금\", \"vi\": \"tiền mặt USD chính xác\"}, \"govFeeDesc3\": {\"en\": \" at Vietnamese border) — \", \"ko\": \"으로 베트남 국경에서 지불) — \", \"vi\": \" tại cửa khẩu Việt Nam) — \"}, \"govFeeDesc4\": {\"en\": \"$25 for tourist\", \"ko\": \"관광은 $25\", \"vi\": \"$25 cho du lịch\"}, \"govFeeDesc5\": {\"en\": \", \", \"ko\": \", \", \"vi\": \", \"}, \"govFeeDesc6\": {\"en\": \"$50 for business\", \"ko\": \"비즈니스는 $50\", \"vi\": \"$50 cho doanh nghiệp\"}, \"govFeeDesc7\": {\"en\": \". ATMs may not be available at land borders — please prepare cash in advance.\", \"ko\": \". 국경에는 ATM이 없을 수 있습니다 — 미리 현금을 준비하십시오.\", \"vi\": \". Cây ATM có thể không có sẵn tại các cửa khẩu đường bộ — vui lòng chuẩn bị tiền mặt trước.\"}, \"serviceFeeDesc\": {\"en\": \" (paid online at checkout) — covers application processing, document review, and visa delivery to your email.\", \"ko\": \" (결제 시 온라인 결제) — 신청 처리, 서류 검토 및 이메일 비자 발송을 포함합니다.\", \"vi\": \" (thanh toán trực tuyến khi đặt hàng) — bao gồm xử lý hồ sơ, kiểm duyệt tài liệu và gửi visa qua email.\"}}, \"extraServices\": [{\"id\": \"vip_fast_track\", \"desc\": {\"en\": \" +$55 per person\", \"ko\": \" 1인당 +$55\", \"vi\": \" +$55 mỗi người\"}, \"name\": {\"en\": \"VIP Airport Fast-track:\", \"ko\": \"VIP 공항 패스트 트랙:\", \"vi\": \"Đón khách VIP tại sân bay:\"}}, {\"id\": \"car_pick_up\", \"desc\": {\"en\": \" price varies by distance — contact support for a quote\", \"ko\": \" 거리에 따라 가격이 다릅니다 — 견적은 지원팀에 문의하십시오\", \"vi\": \" giá thay đổi theo khoảng cách — liên hệ hỗ trợ để nhận báo giá\"}, \"name\": {\"en\": \"Car pick-up:\", \"ko\": \"차량 픽업:\", \"vi\": \"Xe đưa đón:\"}}], \"paxDiscountTiers\": [{\"key\": \"1_person\", \"icon\": \"User\", \"label\": {\"en\": \"1 Person\", \"ko\": \"1 명\", \"vi\": \"1 Người\"}, \"discount\": 0, \"multiplier\": 1}, {\"key\": \"2_3_persons\", \"icon\": \"Users\", \"label\": {\"en\": \"2–3 Persons\", \"ko\": \"2–3 명\", \"vi\": \"2–3 Người\"}, \"discount\": 7, \"multiplier\": 0.93}, {\"key\": \"4_5_persons\", \"icon\": \"UsersRound\", \"label\": {\"en\": \"4–5 Persons\", \"ko\": \"4–5 명\", \"vi\": \"4–5 Người\"}, \"discount\": 12, \"multiplier\": 0.88}, {\"key\": \"6_plus_persons\", \"icon\": \"Building2\", \"label\": {\"en\": \"6+ Persons\", \"ko\": \"6+ 명\", \"vi\": \"6+ Người\"}, \"discount\": 18, \"multiplier\": 0.82}]}', '2026-06-24 03:09:09.071', '2026-06-24 03:09:09.071');
INSERT INTO `page_settings` VALUES ('aa4155f4-4751-49de-aef6-5d5fc10c69f0', 'emergency-inquiry', '{\"hero\": {\"en\": {\"title\": \"Emergency Visa Support\", \"subtitle\": \"Urgent processing for immediate travel needs.\", \"alert_title\": \"IMPORTANT NOTICE\", \"alert_desc_link\": \"contact us directly\", \"alert_desc_prefix\": \"For flights departing within 24 hours, please\", \"alert_desc_suffix\": \"via WhatsApp for immediate assistance.\"}, \"ko\": {\"title\": \"긴급 비자 지원\", \"subtitle\": \"즉각적인 여행 필요를 위한 긴급 처리.\", \"alert_title\": \"중요 공지\", \"alert_desc_link\": \"직접 연락\", \"alert_desc_prefix\": \"24시간 이내에 출발하는 항공편의 경우,\", \"alert_desc_suffix\": \"하여 WhatsApp을 통해 즉각적인 지원을 받으세요.\"}, \"vi\": {\"title\": \"Hỗ Trợ Visa Khẩn Cấp\", \"subtitle\": \"Xử lý khẩn cấp cho nhu cầu du lịch ngay lập tức.\", \"alert_title\": \"THÔNG BÁO QUAN TRỌNG\", \"alert_desc_link\": \"liên hệ trực tiếp\", \"alert_desc_prefix\": \"Đối với các chuyến bay khởi hành trong vòng 24 giờ, vui lòng\", \"alert_desc_suffix\": \"qua WhatsApp để được hỗ trợ ngay lập tức.\"}}, \"pricing\": {\"en\": {\"desc\": \"Choose the speed you need.\", \"tiers\": [{\"id\": \"last-minute\", \"link\": \"https://wa.me/84936699869\", \"name\": \"Last Minute / Holiday\", \"price\": \"Contact Us\", \"bestFor\": \"Boarding soon\", \"timeframe\": \"1-2 Hours\", \"description\": \"Immediate processing for extremely urgent flights.\"}, {\"id\": \"2h\", \"key\": \"URGENT_2WH\", \"link\": \"/apply?speed=2h\", \"name\": \"Express 2 Hours\", \"bestFor\": \"Same day flights\", \"timeframe\": \"2 Hours\", \"description\": \"Receive your visa in just 2 working hours.\", \"isHighlighted\": true}, {\"id\": \"4h\", \"key\": \"URGENT_4WH\", \"link\": \"/apply?speed=4h\", \"name\": \"Express 4 Hours\", \"bestFor\": \"Flights tomorrow\", \"timeframe\": \"4 Hours\", \"description\": \"Receive your visa in 4 working hours.\"}, {\"id\": \"1d\", \"key\": \"URGENT_1WD\", \"link\": \"/apply?speed=1d\", \"name\": \"Express 1 Day\", \"bestFor\": \"Weekend flights\", \"timeframe\": \"1 Working Day\", \"description\": \"Get your visa by the next working day.\"}, {\"id\": \"2d\", \"key\": \"URGENT_2WD_30\", \"link\": \"/apply?speed=2d\", \"name\": \"Super Urgent 2 Days\", \"bestFor\": \"Planned trips\", \"timeframe\": \"2 Working Days\", \"description\": \"Fast track your visa in 2 days.\"}], \"title\": \"Emergency Processing Options\", \"best_for\": \"Best for:\", \"apply_btn\": \"Apply Now\", \"service_fee\": \"Service Fee\", \"whatsapp_btn\": \"WhatsApp Us\", \"most_requested\": \"MOST REQUESTED\", \"pricing_unavailable\": \"Pricing is currently unavailable.\"}, \"ko\": {\"desc\": \"필요한 속도를 선택하세요.\", \"tiers\": [{\"id\": \"last-minute\", \"link\": \"https://wa.me/84936699869\", \"name\": \"막바지 / 휴일\", \"price\": \"문의하기\", \"bestFor\": \"곧 탑승\", \"timeframe\": \"1-2 시간\", \"description\": \"극히 긴급한 항공편을 위한 즉각적인 처리.\"}, {\"id\": \"2h\", \"key\": \"URGENT_2WH\", \"link\": \"/apply?speed=2h\", \"name\": \"초특급 2시간\", \"bestFor\": \"당일 항공편\", \"timeframe\": \"2 시간\", \"description\": \"단 2시간 만에 비자를 받으세요.\", \"isHighlighted\": true}, {\"id\": \"4h\", \"key\": \"URGENT_4WH\", \"link\": \"/apply?speed=4h\", \"name\": \"특급 4시간\", \"bestFor\": \"내일 항공편\", \"timeframe\": \"4 시간\", \"description\": \"4시간 만에 비자를 받으세요.\"}, {\"id\": \"1d\", \"key\": \"URGENT_1WD\", \"link\": \"/apply?speed=1d\", \"name\": \"특급 1일\", \"bestFor\": \"주말 항공편\", \"timeframe\": \"영업일 1일\", \"description\": \"다음 영업일까지 비자를 받으세요.\"}, {\"id\": \"2d\", \"key\": \"URGENT_2WD_30\", \"link\": \"/apply?speed=2d\", \"name\": \"매우 긴급 2일\", \"bestFor\": \"계획된 여행\", \"timeframe\": \"영업일 2일\", \"description\": \"이틀 만에 비자를 빠르게 받으세요.\"}], \"title\": \"긴급 처리 옵션\", \"best_for\": \"추천 대상:\", \"apply_btn\": \"지금 신청\", \"service_fee\": \"서비스 요금\", \"whatsapp_btn\": \"WhatsApp 문의\", \"most_requested\": \"가장 많이 요청됨\", \"pricing_unavailable\": \"현재 가격을 확인할 수 없습니다.\"}, \"vi\": {\"desc\": \"Chọn tốc độ bạn cần.\", \"tiers\": [{\"id\": \"last-minute\", \"link\": \"https://wa.me/84936699869\", \"name\": \"Cấp Bách / Ngày Lễ\", \"price\": \"Liên hệ\", \"bestFor\": \"Sắp lên máy bay\", \"timeframe\": \"1-2 Giờ\", \"description\": \"Xử lý ngay lập tức cho các chuyến bay cực kỳ khẩn cấp.\"}, {\"id\": \"2h\", \"key\": \"URGENT_2WH\", \"link\": \"/apply?speed=2h\", \"name\": \"Hỏa tốc 2 Giờ\", \"bestFor\": \"Chuyến bay trong ngày\", \"timeframe\": \"2 Giờ\", \"description\": \"Nhận visa chỉ trong 2 giờ làm việc.\", \"isHighlighted\": true}, {\"id\": \"4h\", \"key\": \"URGENT_4WH\", \"link\": \"/apply?speed=4h\", \"name\": \"Hỏa tốc 4 Giờ\", \"bestFor\": \"Chuyến bay ngày mai\", \"timeframe\": \"4 Giờ\", \"description\": \"Nhận visa trong 4 giờ làm việc.\"}, {\"id\": \"1d\", \"key\": \"URGENT_1WD\", \"link\": \"/apply?speed=1d\", \"name\": \"Hỏa tốc 1 Ngày\", \"bestFor\": \"Chuyến bay cuối tuần\", \"timeframe\": \"1 Ngày làm việc\", \"description\": \"Nhận visa vào ngày làm việc tiếp theo.\"}, {\"id\": \"2d\", \"key\": \"URGENT_2WD_30\", \"link\": \"/apply?speed=2d\", \"name\": \"Rất Khẩn 2 Ngày\", \"bestFor\": \"Chuyến đi đã lên lịch\", \"timeframe\": \"2 Ngày làm việc\", \"description\": \"Rút ngắn thời gian nhận visa trong 2 ngày.\"}], \"title\": \"Tùy chọn Xử lý Khẩn cấp\", \"best_for\": \"Tốt nhất cho:\", \"apply_btn\": \"Đăng ký ngay\", \"service_fee\": \"Phí dịch vụ\", \"whatsapp_btn\": \"Liên hệ WhatsApp\", \"most_requested\": \"ĐƯỢC YÊU CẦU NHIỀU NHẤT\", \"pricing_unavailable\": \"Bảng giá hiện không có sẵn.\"}}, \"timeline\": {\"en\": {\"desc\": \"How we expedite your application.\", \"steps\": [{\"icon\": \"FileText\", \"title\": \"Submit Request\", \"number\": 1, \"description\": \"Fill out the emergency form with flight details.\"}, {\"icon\": \"Send\", \"title\": \"Quick Processing\", \"number\": 2, \"description\": \"Our team prioritizes your application immediately.\"}, {\"icon\": \"Mail\", \"title\": \"Receive Visa\", \"number\": 3, \"description\": \"Get your approval letter via email.\"}], \"title\": \"Emergency Process Timeline\"}, \"ko\": {\"desc\": \"신청서를 신속하게 처리하는 방법.\", \"steps\": [{\"icon\": \"FileText\", \"title\": \"요청 제출\", \"number\": 1, \"description\": \"항공편 세부 정보와 함께 긴급 양식을 작성하세요.\"}, {\"icon\": \"Send\", \"title\": \"빠른 처리\", \"number\": 2, \"description\": \"팀에서 신청서를 즉시 우선 처리합니다.\"}, {\"icon\": \"Mail\", \"title\": \"비자 수령\", \"number\": 3, \"description\": \"이메일로 승인서를 받으세요.\"}], \"title\": \"긴급 처리 절차\"}, \"vi\": {\"desc\": \"Cách chúng tôi rút ngắn thời gian xử lý.\", \"steps\": [{\"icon\": \"FileText\", \"title\": \"Gửi Yêu Cầu\", \"number\": 1, \"description\": \"Điền form khẩn cấp với chi tiết chuyến bay.\"}, {\"icon\": \"Send\", \"title\": \"Xử Lý Nhanh\", \"number\": 2, \"description\": \"Đội ngũ ưu tiên hồ sơ của bạn ngay lập tức.\"}, {\"icon\": \"Mail\", \"title\": \"Nhận Visa\", \"number\": 3, \"description\": \"Nhận công văn chấp thuận qua email.\"}], \"title\": \"Quy trình xử lý khẩn cấp\"}}}', '2026-06-23 02:55:39.495', '2026-06-24 13:20:26.206');
INSERT INTO `page_settings` VALUES ('ac35c511-3921-4a1d-9665-dadfe588c2ff', 'home', '{\"hero\": {\"en\": {\"eyebrow\": \"Official eVisa Portal\", \"apply_now\": \"Apply Now\", \"headline_1\": \"Apply for your\", \"headline_2\": \"Vietnam E-Visa\", \"headline_3\": \"Online\", \"check_status\": \"Check Status\", \"stat_1_label\": \"Visas Approved\", \"stat_1_value\": \"150,000+\", \"stat_2_label\": \"Fastest Processing\", \"stat_2_value\": \"24h\", \"stat_3_label\": \"Trustpilot Score\", \"stat_3_value\": \"4.9★\", \"subheadline_1\": \"Get your visa to Vietnam fast and securely.\", \"subheadline_2\": \"100% money-back\", \"subheadline_3\": \"if rejected.\"}, \"ko\": {\"eyebrow\": \"공식 E-Visa 포털\", \"apply_now\": \"지금 신청\", \"headline_1\": \"온라인으로\", \"headline_2\": \"베트남 E-Visa\", \"headline_3\": \"신청하기\", \"check_status\": \"진행 상황 확인\", \"stat_1_label\": \"비자 발급 완료\", \"stat_1_value\": \"150,000+\", \"stat_2_label\": \"가장 빠른 처리\", \"stat_2_value\": \"24h\", \"stat_3_label\": \"트러스트파일럿 평점\", \"stat_3_value\": \"4.9★\", \"subheadline_1\": \"빠르고 안전하게 베트남 비자를 받으세요.\", \"subheadline_2\": \"거절 시 100% 환불\", \"subheadline_3\": \"보장.\"}, \"vi\": {\"eyebrow\": \"Cổng E-Visa Chính Thức\", \"apply_now\": \"Đăng ký ngay\", \"headline_1\": \"Đăng ký xin\", \"headline_2\": \"E-Visa Việt Nam\", \"headline_3\": \"Trực tuyến\", \"check_status\": \"Kiểm tra\", \"stat_1_label\": \"Visa đã cấp\", \"stat_1_value\": \"150,000+\", \"stat_2_label\": \"Xử lý nhanh nhất\", \"stat_2_value\": \"24h\", \"stat_3_label\": \"Điểm Trustpilot\", \"stat_3_value\": \"4.9★\", \"subheadline_1\": \"Nhận visa Việt Nam nhanh chóng và an toàn.\", \"subheadline_2\": \"Hoàn tiền 100%\", \"subheadline_3\": \"nếu bị từ chối.\"}}, \"howItWorks\": {\"en\": {\"desc\": \"Get your Vietnam e-Visa in 3 simple steps\", \"title\": \"How It Works\"}, \"ko\": {\"desc\": \"단 3단계로 베트남 e-Visa를 받으세요\", \"title\": \"신청 방법\"}, \"vi\": {\"desc\": \"Nhận e-Visa Việt Nam chỉ với 3 bước đơn giản\", \"title\": \"Quy trình thực hiện\"}}, \"trustSignals\": {\"en\": {\"title\": \"Trusted by Travelers Worldwide\", \"stat_1\": \"Visas Approved\", \"stat_2\": \"Fastest Processing\", \"stat_3\": \"Trustpilot Score\", \"stat_4\": \"Countries Supported\"}, \"ko\": {\"title\": \"전 세계 여행자들이 신뢰하는 서비스\", \"stat_1\": \"비자 발급 완료\", \"stat_2\": \"가장 빠른 처리\", \"stat_3\": \"트러스트파일럿 평점\", \"stat_4\": \"지원 국가\"}, \"vi\": {\"title\": \"Được tin dùng bởi du khách toàn cầu\", \"stat_1\": \"Visa đã cấp\", \"stat_2\": \"Xử lý nhanh nhất\", \"stat_3\": \"Điểm Trustpilot\", \"stat_4\": \"Quốc gia hỗ trợ\"}}, \"pricingPreview\": {\"en\": {\"desc\": \"Choose the processing time that fits your travel schedule. No hidden fees.\", \"title\": \"Clear & Transparent Pricing\", \"popular\": \"Popular\", \"apply_btn\": \"Apply Now\", \"best_value\": \"Best Value\", \"per_person\": \"per person\", \"see_full_pricing\": \"See full pricing & add-ons\"}, \"ko\": {\"desc\": \"여행 일정에 맞는 처리 시간을 선택하세요. 숨겨진 수수료가 없습니다.\", \"title\": \"투명하고 명확한 가격\", \"popular\": \"인기\", \"apply_btn\": \"지금 신청\", \"best_value\": \"최고의 선택\", \"per_person\": \"1인당\", \"see_full_pricing\": \"전체 가격 및 부가 서비스 보기\"}, \"vi\": {\"desc\": \"Chọn thời gian xử lý phù hợp với lịch trình của bạn. Không phí ẩn.\", \"title\": \"Bảng giá minh bạch\", \"popular\": \"Phổ biến\", \"apply_btn\": \"Đăng ký ngay\", \"best_value\": \"Khuyên dùng\", \"per_person\": \"mỗi người\", \"see_full_pricing\": \"Xem toàn bộ bảng giá & dịch vụ\"}}}', '2026-06-23 02:55:39.455', '2026-06-24 13:20:26.166');
