INSERT INTO `page_settings` VALUES ('ff6a66de-9e26-4e04-8ba3-b2b423fb97f6', 'about-us', '{\"hero\": {\"en\": {\"title\": \"We Are <accent>FastVisa.</accent>\", \"subtitle\": \"One of the most recommended Vietnam visa services worldwide.<br/>Pioneering seamless global mobility with 15+ years of trusted expertise.\"}, \"ko\": {\"title\": \"우리는 <accent>FastVisa</accent> 입니다.\", \"subtitle\": \"전 세계적으로 가장 추천받는 베트남 비자 서비스 중 하나입니다.<br/>15년 이상의 신뢰할 수 있는 전문성으로 원활한 글로벌 이동을 선도합니다.\"}, \"vi\": {\"title\": \"Chúng tôi là <accent>FastVisa.</accent>\", \"subtitle\": \"Một trong những dịch vụ visa Việt Nam được khuyên dùng nhất thế giới.<br/>Tiên phong mang lại sự di chuyển toàn cầu mượt mà với hơn 15 năm kinh nghiệm đáng tin cậy.\"}}, \"team\": {\"en\": {\"label\": \"Expert Assistance\", \"title\": \"Our Core Team\", \"ctaDesc\": \"Our specialists are always ready to review your files and provide custom solutions for group travel or business entries.\", \"ctaTitle\": \"Have questions about Vietnam Visa requirements?\", \"ctaButton\": \"Contact Our Team\"}, \"ko\": {\"label\": \"전문가 지원\", \"title\": \"우리의 핵심 팀\", \"ctaDesc\": \"저희 전문가들은 언제든지 귀하의 파일을 검토하고 그룹 여행이나 비즈니스 입국을 위한 맞춤형 솔루션을 제공할 준비가 되어 있습니다.\", \"ctaTitle\": \"베트남 비자 요구 사항에 대한 질문이 있으신가요?\", \"ctaButton\": \"우리 팀에 연락하기\"}, \"vi\": {\"label\": \"Hỗ Trợ Chuyên Gia\", \"title\": \"Đội Ngũ Cốt Lõi Của Chúng Tôi\", \"ctaDesc\": \"Các chuyên gia của chúng tôi luôn sẵn sàng xem xét hồ sơ của bạn và đưa ra giải pháp tùy chỉnh cho các chuyến đi theo nhóm hoặc nhập cảnh công tác.\", \"ctaTitle\": \"Bạn có câu hỏi về yêu cầu Visa Việt Nam?\", \"ctaButton\": \"Liên Hệ Nhóm Chúng Tôi\"}}, \"quote\": {\"en\": {\"text\": \"“Vietnam\'s e-visa service has become remarkably streamlined — services like FastVisa make the application process effortless for international travelers visiting one of Southeast Asia\'s most spectacular destinations.”\", \"author\": \"The New York Times\", \"section\": \"Travel Section\"}, \"ko\": {\"text\": \"“베트남의 e-비자 서비스는 눈에 띄게 간소화되었습니다. FastVisa와 같은 서비스는 동남아시아에서 가장 멋진 목적지 중 하나를 방문하는 국제 여행객들의 신청 과정을 수월하게 만들어줍니다.”\", \"author\": \"The New York Times\", \"section\": \"여행 섹션\"}, \"vi\": {\"text\": \"“Dịch vụ e-visa của Việt Nam đã trở nên cực kỳ tinh gọn — những dịch vụ như FastVisa làm cho quá trình xin visa trở nên dễ dàng đối với du khách quốc tế đến thăm một trong những điểm đến ngoạn mục nhất Đông Nam Á.”\", \"author\": \"The New York Times\", \"section\": \"Mục Du Lịch\"}}, \"whyUs\": [\"Target\", \"Shield\", \"Award\", \"Users\", \"Shield\"], \"mission\": {\"en\": {\"label\": \"Our Purpose\", \"title\": \"Our Mission\", \"description\": \"We help travelers obtain Vietnam visas on time with transparent pricing, secure document handling, and responsive support. Easy application, no hidden charges, and a service guarantee backed by our money-back policy for eligible cases.\", \"hassleFreeDesc\": \"Streamlining documents so you can focus on the travel experience.\", \"hassleFreeTitle\": \"Hassle-Free Process\", \"reliabilityDesc\": \"Direct updates and secure channels ensure your personal data is safe.\", \"reliabilityTitle\": \"Absolute Reliability\"}, \"ko\": {\"label\": \"우리의 목적\", \"title\": \"우리의 사명\", \"description\": \"우리는 투명한 가격, 안전한 문서 처리, 신속한 지원을 통해 여행자가 베트남 비자를 제때 발급받을 수 있도록 돕습니다. 쉬운 신청, 숨겨진 비용 없음, 적격한 경우 환불 정책이 지원되는 서비스 보장.\", \"hassleFreeDesc\": \"여행 경험에 집중할 수 있도록 문서를 간소화합니다.\", \"hassleFreeTitle\": \"번거로움 없는 과정\", \"reliabilityDesc\": \"직접적인 업데이트와 보안 채널을 통해 개인 데이터가 안전하게 보호됩니다.\", \"reliabilityTitle\": \"절대적인 신뢰성\"}, \"vi\": {\"label\": \"Mục Tiêu Của Chúng Tôi\", \"title\": \"Sứ Mệnh Của Chúng Tôi\", \"description\": \"Chúng tôi giúp du khách nhận visa Việt Nam đúng hạn với giá cả minh bạch, xử lý hồ sơ an toàn và hỗ trợ nhiệt tình. Đăng ký dễ dàng, không phí ẩn và dịch vụ được bảo đảm bằng chính sách hoàn tiền cho các trường hợp đủ điều kiện.\", \"hassleFreeDesc\": \"Tối ưu hóa giấy tờ để bạn có thể tập trung vào trải nghiệm du lịch.\", \"hassleFreeTitle\": \"Quy Trình Nhanh Gọn\", \"reliabilityDesc\": \"Cập nhật trực tiếp và các kênh bảo mật đảm bảo dữ liệu cá nhân của bạn được an toàn.\", \"reliabilityTitle\": \"Độ Tin Cậy Tuyệt Đối\"}}, \"features\": {\"en\": {\"items\": {\"prices\": {\"title\": \"Competitive Prices\", \"description\": \"Best value for standard and urgent processing.\"}, \"delivery\": {\"title\": \"99% On-Time Delivery\", \"description\": \"Applications processed within promised timeframe.\"}, \"guarantee\": {\"title\": \"Money-Back Guarantee\", \"description\": \"Eligible rejections covered by our guarantee policy.\"}, \"experience\": {\"title\": \"15+ Years Experience\", \"description\": \"Trusted by travelers worldwide since 2009.\"}, \"noHiddenCharges\": {\"title\": \"No Hidden Charges\", \"description\": \"Transparent pricing from quote to checkout.\"}}, \"label\": \"Why Choose Us\", \"title\": \"Why Apply With Us\"}, \"ko\": {\"items\": {\"prices\": {\"title\": \"경쟁력 있는 가격\", \"description\": \"표준 및 긴급 처리를 위한 최고의 가치.\"}, \"delivery\": {\"title\": \"99% 정시 배달\", \"description\": \"약속된 시간 내에 처리되는 신청서.\"}, \"guarantee\": {\"title\": \"환불 보장\", \"description\": \"환불 보장 정책이 적용되는 적격한 거절 사례.\"}, \"experience\": {\"title\": \"15년 이상의 경험\", \"description\": \"2009년부터 전 세계 여행객들에게 신뢰받고 있습니다.\"}, \"noHiddenCharges\": {\"title\": \"숨겨진 비용 없음\", \"description\": \"견적부터 결제까지 투명한 가격.\"}}, \"label\": \"우리를 선택하는 이유\", \"title\": \"왜 우리와 함께 신청해야 하는가\"}, \"vi\": {\"items\": {\"prices\": {\"title\": \"Giá Cả Cạnh Tranh\", \"description\": \"Giá trị tốt nhất cho dịch vụ tiêu chuẩn và khẩn cấp.\"}, \"delivery\": {\"title\": \"Giao Hẹn Đúng Hạn 99%\", \"description\": \"Hồ sơ được xử lý trong khoảng thời gian đã cam kết.\"}, \"guarantee\": {\"title\": \"Bảo Đảm Hoàn Tiền\", \"description\": \"Các trường hợp từ chối đủ điều kiện được bảo vệ bởi chính sách.\"}, \"experience\": {\"title\": \"Hơn 15 Năm Kinh Nghiệm\", \"description\": \"Được tin tưởng bởi du khách trên toàn thế giới từ 2009.\"}, \"noHiddenCharges\": {\"title\": \"Không Phí Ẩn\", \"description\": \"Giá cả minh bạch từ báo giá đến thanh toán.\"}}, \"label\": \"Tại Sao Chọn Chúng Tôi\", \"title\": \"Lý Do Đăng Ký Với Chúng Tôi\"}}, \"sceneSlider\": {\"en\": {\"heading\": \"Discover Vietnam\'s Beauty\", \"subheading\": \"From emerald bays to historic cities — your next adventure awaits.\"}, \"ko\": {\"heading\": \"베트남의 아름다움 발견\", \"subheading\": \"에메랄드 만에서 역사적인 도시까지 — 당신의 다음 모험이 기다립니다.\"}, \"vi\": {\"heading\": \"Khám Phá Vẻ Đẹp Việt Nam\", \"subheading\": \"Từ những vịnh ngọc bích đến các thành phố lịch sử — chuyến phiêu lưu tiếp theo đang chờ bạn.\"}}, \"destinations\": [{\"id\": 1, \"img\": \"/images/about-us/sapa.jpg\", \"key\": \"sapa\", \"translations\": {\"en\": {\"desc\": \"A masterpiece of nature and mountainous people.\", \"title\": \"Terraced Fields\", \"location\": \"Sa Pa, Lao Cai\"}, \"ko\": {\"desc\": \"자연과 산악 민족의 걸작.\", \"title\": \"계단식 논\", \"location\": \"사파, 라오까이\"}, \"vi\": {\"desc\": \"Kiệt tác thiên nhiên và con người miền núi Tây Bắc.\", \"title\": \"Ruộng Bậc Thang\", \"location\": \"Sa Pa, Lào Cai\"}}}, {\"id\": 2, \"img\": \"/images/about-us/hoian.jpg\", \"key\": \"hoian\", \"translations\": {\"en\": {\"desc\": \"World cultural heritage with romantic and ancient beauty.\", \"title\": \"Hoi An Ancient Town\", \"location\": \"Quang Nam\"}, \"ko\": {\"desc\": \"로맨틱하고 고풍스러운 아름다움을 지닌 세계 문화 유산.\", \"title\": \"호이안 고도시\", \"location\": \"꽝남\"}, \"vi\": {\"desc\": \"Di sản văn hóa thế giới với vẻ đẹp cổ kính lãng mạn.\", \"title\": \"Phố Cổ Hội An\", \"location\": \"Quảng Nam\"}}}, {\"id\": 3, \"img\": \"/images/about-us/halong.jpg\", \"key\": \"halong\", \"translations\": {\"en\": {\"desc\": \"A natural wonder with thousands of magnificent islands.\", \"title\": \"Ha Long Bay\", \"location\": \"Quang Ninh\"}, \"ko\": {\"desc\": \"수천 개의 웅장한 섬이 있는 자연의 경이로움.\", \"title\": \"하롱베이\", \"location\": \"꽝닌\"}, \"vi\": {\"desc\": \"Kỳ quan thiên nhiên với hàng ngàn hòn đảo kỳ vĩ.\", \"title\": \"Vịnh Hạ Long\", \"location\": \"Quảng Ninh\"}}}, {\"id\": 4, \"img\": \"/images/about-us/danang.jpg\", \"key\": \"danang\", \"translations\": {\"en\": {\"desc\": \"An architectural masterpiece supported by giant hands.\", \"title\": \"Golden Bridge\", \"location\": \"Da Nang\"}, \"ko\": {\"desc\": \"거대한 손이 받치고 있는 건축의 걸작.\", \"title\": \"골든 브릿지\", \"location\": \"다낭\"}, \"vi\": {\"desc\": \"Kiệt tác kiến trúc được nâng đỡ bởi những bàn tay khổng lồ.\", \"title\": \"Cầu Vàng\", \"location\": \"Đà Nẵng\"}}}, {\"id\": 5, \"img\": \"/images/about-us/ninhbinh.jpg\", \"key\": \"ninhbinh\", \"translations\": {\"en\": {\"desc\": \"A scenic complex known as Ha Long Bay on land.\", \"title\": \"Trang An\", \"location\": \"Ninh Binh\"}, \"ko\": {\"desc\": \"육지의 하롱베이로 알려진 경치 좋은 복합 단지.\", \"title\": \"짱안\", \"location\": \"닌빈\"}, \"vi\": {\"desc\": \"Quần thể danh thắng được mệnh danh là Vịnh Hạ Long trên cạn.\", \"title\": \"Tràng An\", \"location\": \"Ninh Bình\"}}}, {\"id\": 6, \"img\": \"/images/about-us/phuquoc.jpg\", \"key\": \"phuquoc\", \"translations\": {\"en\": {\"desc\": \"A beach with smooth white sand and crystal clear water.\", \"title\": \"Sao Beach\", \"location\": \"Phu Quoc\"}, \"ko\": {\"desc\": \"고운 백사장과 수정처럼 맑은 물이 있는 해변.\", \"title\": \"사오 해변\", \"location\": \"푸꾸옥\"}, \"vi\": {\"desc\": \"Bãi biển với bãi cát trắng mịn và làn nước trong xanh.\", \"title\": \"Bãi Sao\", \"location\": \"Phú Quốc\"}}}], \"missionImages\": {\"sapa\": \"/images/about-us/mission-sapa.jpg\", \"hoian\": \"/images/about-us/mission-hoian.jpg\", \"journey\": \"/images/about-us/mission-journey.jpg\"}}', '2026-06-23 02:55:39.463', '2026-06-24 13:20:26.174');
