INSERT INTO `reviews` VALUES ('004ac71e-30fe-493a-a5ec-8f90172a065d', 12, 'Maria Garcia', 'ES', 'https://api.dicebear.com/9.x/fun-emoji/svg?seed=MariaGarcia', 'Very helpful support team. I had an issue with my passport upload, but they guided me step by step. Definitely recommend their service to anyone traveling to Vietnam.', 5, 1, '2026-06-23 09:04:45.336', '2026-06-23 09:04:45.336', 0);
INSERT INTO `reviews` VALUES ('01ea42fd-7c04-4dae-97ef-8f2b8907093f', 9, 'Liam O\'Connor', 'IE', 'https://i.pravatar.cc/150?u=Liam%20O\'Connor', 'Applying for the visa was the easiest part of planning my trip to Vietnam.', 5, 0, '2026-06-23 03:16:23.098', '2026-06-24 10:48:45.821', 0);
INSERT INTO `reviews` VALUES ('04afa48c-7e78-4140-8f5d-f4b5189443d8', 14, 'Sophie Martin', 'FR', 'https://api.dicebear.com/9.x/fun-emoji/svg?seed=SophieMartin', 'Incredible! I thought getting a visa would be complicated, but FASTVISA made it feel like booking a flight. Excellent UI and super clear instructions.', 5, 1, '2026-06-23 09:04:45.363', '2026-06-23 09:04:45.363', 0);
INSERT INTO `reviews` VALUES ('40357bf0-d771-446a-89d6-1a3cc4d01baa', 5, 'Hans Müller', 'DE', 'https://i.pravatar.cc/150?u=Hans%20M%C3%BCller', 'Everything worked perfectly. The document arrived on time for my flight to Hanoi.', 5, 0, '2026-06-23 03:16:23.060', '2026-06-23 03:16:23.060', 0);
INSERT INTO `reviews` VALUES ('5f67bd69-7807-4aa0-a3cd-58e4a40532f2', 13, 'David Lee', 'KR', 'https://api.dicebear.com/9.x/fun-emoji/svg?seed=DavidLee', 'Quick processing and reasonable price compared to other agencies. The website is very modern and easy to use on my phone.', 4, 1, '2026-06-23 09:04:45.350', '2026-06-23 09:04:45.350', 0);
INSERT INTO `reviews` VALUES ('6bb4345b-ed35-4fdb-a046-17e65b076ae0', 7, 'Chloe Martin', 'FR', 'https://i.pravatar.cc/150?u=Chloe%20Martin', 'The application form is straightforward. Got my visa quickly. Thank you!', 5, 0, '2026-06-23 03:16:23.080', '2026-06-23 03:16:23.080', 0);
INSERT INTO `reviews` VALUES ('727b4095-9d1c-43f5-9b0d-509d8a75d84c', 10, 'Noah Garcia', 'ES', 'https://i.pravatar.cc/150?u=Noah%20Garcia', 'Excellent and fast. I used the urgent service and got it in 1 day.', 5, 0, '2026-06-23 03:16:23.108', '2026-06-24 10:46:42.418', 0);
INSERT INTO `reviews` VALUES ('87564eec-ec8c-4d2f-9ab3-13dd542365de', 3, 'Michael Wang', 'CA', 'https://i.pravatar.cc/150?u=Michael%20Wang', 'Good service, but it took exactly 5 days as stated. I was hoping it would be a bit faster. Still, no complaints.', 4, 0, '2026-06-23 03:16:23.041', '2026-06-23 03:16:23.041', 0);
INSERT INTO `reviews` VALUES ('87cebff2-43db-49b4-9841-a59118b9858a', 1, 'John Smith', 'US', 'https://i.pravatar.cc/150?u=John%20Smith', 'The process was incredibly smooth. I received my e-Visa in just 3 days without any hassle. Highly recommended!', 5, 0, '2026-06-23 03:16:23.009', '2026-06-23 03:16:23.009', 0);
INSERT INTO `reviews` VALUES ('a20b3ba0-37d7-4b33-83e1-ec98e96dbd66', 11, 'John Smith', 'US', 'https://api.dicebear.com/9.x/fun-emoji/svg?seed=JohnSmith', 'Outstanding service! My e-Visa was approved in less than 24 hours. The whole process was completely stress-free and very straightforward.', 5, 1, '2026-06-23 09:04:45.310', '2026-06-23 09:04:45.310', 0);
INSERT INTO `reviews` VALUES ('af753a6d-987b-451c-9cec-45fec609ec74', 2, 'Sarah Connor', 'GB', 'https://i.pravatar.cc/150?u=Sarah%20Connor', 'Very fast and reliable service. The support team was also helpful when I had a question about my passport upload.', 5, 0, '2026-06-23 03:16:23.031', '2026-06-23 03:16:23.031', 0);
INSERT INTO `reviews` VALUES ('b03b935d-9ed4-4f90-bb58-1c398b3ad31a', 17, 'Liam Johnson', 'AU', 'https://api.dicebear.com/9.x/fun-emoji/svg?seed=LiamJohnson', 'Best visa service I\'ve ever used! No hidden fees, instant confirmation, and great peace of mind before my holiday. Cheers!', 5, 1, '2026-06-23 09:04:45.393', '2026-06-24 12:06:39.377', 1);
INSERT INTO `reviews` VALUES ('b73f2fa8-7c02-4ff9-b1ff-1586da9bb534', 16, 'Yuki Tanaka', 'JP', 'https://api.dicebear.com/9.x/fun-emoji/svg?seed=YukiTanaka', 'Very good service. The email updates were prompt and informative. I never had to wonder what the status of my application was.', 4, 1, '2026-06-23 09:04:45.382', '2026-06-24 12:06:41.792', 1);
INSERT INTO `reviews` VALUES ('c63c0c58-24bb-498b-9dc4-b61fc4f8015d', 19, 'Carlos Silva', 'BR', 'https://api.dicebear.com/9.x/fun-emoji/svg?seed=CarlosSilva', 'Super fast and very reliable. I submitted my application on Sunday night and got it on Monday afternoon! 10/10.', 5, 1, '2026-06-23 09:04:45.411', '2026-06-24 12:06:34.389', 1);
INSERT INTO `reviews` VALUES ('e1892834-d956-499b-8db5-918b46368676', 15, 'Oliver Brown', 'GB', 'https://api.dicebear.com/9.x/fun-emoji/svg?seed=OliverBrown', 'Flawless experience. Got my approval letter exactly when promised. Trusted and reliable. I will be using them for my future trips.', 5, 1, '2026-06-23 09:04:45.372', '2026-06-24 12:08:25.781', 1);
INSERT INTO `reviews` VALUES ('f1f03c66-deec-4c0e-a4e7-60384384e7f8', 4, 'Emma Johnson', 'AU', 'https://i.pravatar.cc/150?u=Emma%20Johnson', 'Super easy to use interface. The pricing was transparent and the email updates kept me informed.', 5, 0, '2026-06-23 03:16:23.052', '2026-06-23 03:16:23.052', 0);
INSERT INTO `reviews` VALUES ('f3702383-3474-4486-bf71-606452785720', 20, 'Emma Wilson', 'CA', 'https://api.dicebear.com/9.x/fun-emoji/svg?seed=EmmaWilson', 'Good experience overall. Easy form to fill out, and secure payment process. Took the hassle out of traveling planning.', 4, 1, '2026-06-23 09:04:45.420', '2026-06-24 12:08:37.577', 0);
INSERT INTO `reviews` VALUES ('f4dd45d3-f661-4180-96cf-67b95a30c291', 8, 'Isabella Rossi', 'IT', 'https://i.pravatar.cc/150?u=Isabella%20Rossi', 'Great customer support. I made a mistake on my application and they helped me fix it immediately.', 4, 0, '2026-06-23 03:16:23.088', '2026-06-23 03:16:23.088', 0);
INSERT INTO `reviews` VALUES ('fc28ae65-b7b7-4164-b4cd-7a909edc0a27', 18, 'Anna Schmidt', 'DE', 'https://api.dicebear.com/9.x/fun-emoji/svg?seed=AnnaSchmidt', 'Professional, fast, and transparent. The interface is beautiful, not like government sites. Highly recommended for all travelers.', 5, 1, '2026-06-23 09:04:45.402', '2026-06-24 12:06:36.545', 1);
INSERT INTO `reviews` VALUES ('fcad12aa-bd43-4138-a348-7e11faaf8b64', 6, 'Yuki Tanaka', 'JP', 'https://i.pravatar.cc/150?u=Yuki%20Tanaka', 'Very convenient service. I didn\'t have to visit the embassy at all.', 5, 0, '2026-06-23 03:16:23.070', '2026-06-23 03:16:23.070', 0);
