INSERT INTO `team_members` VALUES ('29ec801a-9a91-4893-b548-292fb42d7fb1', 'Khanh Bao', '{\"en\":\"Co-founder & Marketing\",\"vi\":\"Đồng sáng lập – Marketing\",\"ko\":\"공동 창립자 - 마케팅\"}', '{\"en\":\"Builds and implements marketing, communications, and content activities; searches for customers and develops outreach channels; coordinates with consultants to understand market needs.\",\"vi\":\"Xây dựng và triển khai các hoạt động marketing, truyền thông, nội dung; tìm kiếm khách hàng và phát triển kênh tiếp cận; phối hợp với người tư vấn để hiểu nhu cầu thị trường.\",\"ko\":\"마케팅, 커뮤니케이션 및 콘텐츠 활동을 기획하고 실행합니다. 고객을 발굴하고 접근 채널을 개발하며 컨설턴트와 협력하여 시장의 요구를 파악합니다.\"}', '/Picture3.png', '#bfdbfe', 1, 1, '2026-06-24 13:20:26.188', '2026-06-24 13:20:26.188');
INSERT INTO `team_members` VALUES ('58dc8be6-d5f1-4612-b63f-72ce592280ff', 'Dat Tong', '{\"en\":\"Co-founder & Visa Consultant\",\"vi\":\"Đồng sáng lập – Tư vấn Visa\",\"ko\":\"공동 창립자 및 비자 컨설턴트\"}', '{\"en\":\"Directly meets and advises clients, handles visa applications and procedures; ensures accurate and compliant business processes; acts as a bridge for real-world customer feedback for the team.\",\"vi\":\"Trực tiếp gặp gỡ, tư vấn khách hàng và xử lý hồ sơ, thủ tục visa; đảm bảo quy trình nghiệp vụ chính xác, đúng quy định; là cầu nối phản hồi thực tế từ khách hàng cho cả nhóm.\",\"ko\":\"고객과 직접 만나 상담하고 비자 신청 및 절차를 처리합니다. 정확하고 규정에 맞는 업무 프로세스를 보장하며, 팀을 위한 고객의 생생한 피드백 전달자 역할을 합니다.\"}', '/Picture2.png', '#fef08a', 3, 1, '2026-06-24 13:20:26.200', '2026-06-24 13:20:26.200');
INSERT INTO `team_members` VALUES ('aafcfdb2-ae5c-441d-b8ce-571e9b58185a', 'Viet Nguyen', '{\"en\":\"Co-founder & Technology\",\"vi\":\"Đồng sáng lập – Công nghệ\",\"ko\":\"공동 창립자 - 기술\"}', '{\"en\":\"Responsible for developing and operating the technology platform, ensuring the website system runs stably and securely. Directly builds core features such as the smart AI assistant, automated payment gateway, and passport scanning technology.\",\"vi\":\"Chịu trách nhiệm phát triển và vận hành nền tảng công nghệ, đảm bảo hệ thống website luôn hoạt động ổn định và bảo mật. Trực tiếp xây dựng các tính năng cốt lõi như trợ lý AI thông minh, cổng thanh toán và công nghệ quét hộ chiếu.\",\"ko\":\"기술 플랫폼 개발 및 운영을 담당하여 웹사이트 시스템이 안정적이고 안전하게 실행되도록 보장합니다. 스마트 AI 비서, 자동 결제 게이트웨이 및 여권 스캔 기술과 같은 핵심 기능을 직접 구축합니다.\"}', '/Picture1.png', '#e2e8f0', 2, 1, '2026-06-24 13:20:26.194', '2026-06-24 13:20:26.194');
